from agent import *from models.products import *import simplejsondef run(context, session):    cats_links = ['makeup', 'skin-care', 'perfumes-1', 'hair-1', 'bath-body-1', 'nails', 'men-collection', 'kids-babies']    for link in cats_links:        url = 'https://www.searchanise.com/getresults?api_key=7I9N0F6L4v&q=&sortBy=total_reviews&sortOrder=desc&startIndex={start}&maxResults=250&collection={link}&output=jsonp'.format(start=0, link=link)        session.queue(Request(url), process_prodlist, dict(link=link, start=0))def process_prodlist(data, context, session):    json = simplejson.loads(data.content)    prods = json['items']    for prod in prods:        name = prod['title']        brand = prod['vendor']        cat = json['shopify_collection']['title'].rstrip('.')        ssid = prod['product_id']        sku = prod.get('product_code')        url = 'https://feel22.com' + prod['link']        revs_count = prod.get('total_reviews')        if revs_count and int(revs_count) > 0:            revs_url = 'https://stamped.io/api/widget?productId={ssid}&apiKey=pubkey-9DajnAm17lctkg5Q1Jn859D09iIcT8&storeUrl=glam22.myshopify.com&take=9999&sort=most-votes'.format(ssid=ssid)            session.do(Request(revs_url), process_reviews, dict(context, cat=cat, name=name, url=url, ssid=ssid, sku=sku, brand=brand))    prods_count = json['totalItems']    per_page = 250    if context['start'] < prods_count:        start = context['start'] + per_page        next_url = 'https://www.searchanise.com/getresults?api_key=7I9N0F6L4v&q=&sortBy=total_reviews&sortOrder=desc&startIndex={start}&maxResults=250&collection={link}&output=jsonp'.format(start=start, link=context['link'])        session.queue(Request(next_url), process_prodlist, dict(context, start=start))def process_reviews(data, context, session):    product = Product()    product.name = context['name']    product.category = context['cat']    product.url = context['url']    product.ssid = context['ssid']    product.manufacturer = context['brand']    sku = context.get('sku')    if sku:        product.sku = sku.split('SKU-')[-1]    json = simplejson.loads(data.content)    new_data = data.parse_fragment(json['widget'])    revs = new_data.xpath('//div[@class="stamped-review"]')    for rev in revs:        review = Review()        review.type = 'user'        review.ssid = rev.xpath('@id').string().split('-')[-1]        review.url = product.url        review.title = rev.xpath('.//h3[@class="stamped-review-header-title"]//text()').string()        review.date = rev.xpath('.//div[@class="created"]//text()').string()        author = rev.xpath('.//strong[@class="author"]//text()').string()        if author:            review.authors.append(Person(name=author, ssid=author))        grade_overall = rev.xpath('.//span[@class="stamped-starratings stamped-review-header-starratings"]/@data-rating').string()        if grade_overall:            review.grades.append(Grade(type='overall', value=float(grade_overall), best=5.0))        is_verified = rev.xpath('.//span[@data-type="buyer"]/@data-verified-label').string()        if is_verified:            review.add_property(type='is_verified_buyer', value=True)        else:            continue        is_recommended = rev.xpath('.//div[@class="stamped-review-recommend"]/@data-is-recommend').string()        if is_recommended == "true":            review.add_property(value=True, type='is_recommended')        hlp_yes = rev.xpath('.//i[@class="stamped-fa stamped-fa-thumbs-up"]//text()').string()        if hlp_yes:            review.add_property(type='helpful_votes', value=int(hlp_yes))        hlp_no = rev.xpath('.//i[@class="stamped-fa stamped-fa-thumbs-down"]//text()').string()        if hlp_no:            review.add_property(type='not_helpful_votes', value=int(hlp_no))        excerpt = rev.xpath('.//p[@class="stamped-review-content-body"]//text()').string(multiple=True)        if excerpt:            review.add_property(type='excerpt', value=excerpt)            product.reviews.append(review)    if product.reviews:        session.emit(product)    # no next page, loaded 9999 reviews